const item = $input.first().json;
const body = item.body || item;
const data = body.data || {};
const key = data.key || {};
const msg = data.message || {};

const pushName = data.pushName || body.pushName || "";
const remetente = key.remoteJid || body.remoteJid || body.sender || "";
const fromMe = key.fromMe === true;
const mensagem = msg.conversation
  || msg.extendedTextMessage?.text
  || msg.imageMessage?.caption
  || msg.documentMessage?.caption
  || msg.videoMessage?.caption
  || "";
const msgType = data.messageType || "";
const destinatario = body.sender || "";

return [{
  json: {
    pushName,
    remetente,
    fromMe,
    msg: mensagem,
    msgType,
    destinatario
  }
}];

const apiResponse = $input.first().json;
const extData = $node["Extrair dados"].json;
const remetente = extData.remetente || "";
const numero = remetente.replace("@s.whatsapp.net", "").replace("@lid", "");

const contatos = (apiResponse.success && Array.isArray(apiResponse.data)) ? apiResponse.data : [];
const encontrado = contatos.some(c => {
  const jid = c.remoteJid || "";
  return jid.replace("@s.whatsapp.net", "").replace("@lid", "") === numero;
});

return [{
  json: {
    ...extData,
    contatoConhecido: encontrado
  }
}];

const extItems = $items("Extrair dados");
const extData = (extItems && extItems.length > 0) ? extItems[0].json : {};

// Filtra mensagens enviadas por nos (fromMe = true)
if (extData.fromMe === true) {
  return [null];
}

const msg = extData.msg || "";
// Filtra mensagens vazias
if (!msg || msg.trim() === "") {
  return [null];
}

const apiData = $input.first().json;
const remetente = extData.remetente || "";

// Extrai o numero limpo (sem @s.whatsapp.net, @lid, etc)
const numero = remetente.split("@")[0] || remetente;

return [{
  json: {
    remetente: remetente,
    numero: numero,
    pushName: extData.pushName || "",
    msg: msg,
    msgType: extData.msgType || "",
    estado: apiData.estado || "SAUDACAO",
    dados: apiData.dados || {},
    conversaId: apiData.id || null
  }
}];

const item = $input.first().json;
const aiRes = item.output || "";

const remetente = item.remetente || "";
const numero = item.numero || remetente.split("@")[0] || "";
const curEstado = item.estado || "SAUDACAO";
const curDados = item.dados || {};
const msgOriginal = item.msg || "";
const msg = msgOriginal.toLowerCase().trim();

let nextEstado = curEstado;
const dados = JSON.parse(JSON.stringify(curDados));

function extrairDoc(texto) {
  const cnpj = texto.match(/\d{2}\.?\d{3}\.?\d{3}\/?\d{4}-?\d{2}/);
  if (cnpj) return { doc: cnpj[0], tipo: "PJ" };
  const cpf = texto.match(/\d{3}\.?\d{3}\.?\d{3}-?\d{2}/);
  if (cpf) return { doc: cpf[0], tipo: "PF" };
  return null;
}

function detectarTipo(texto) {
  if (/\b(1|pf|fisica|física)\b/.test(texto)) return "PF";
  if (/\b(2|pj|juridica|jurídica|cnpj)\b/.test(texto)) return "PJ";
  return null;
}

function pareceNome(texto) {
  const alpha = texto.replace(/[^a-zA-ZÀ-ÿ ]/g, "").trim();
  return alpha.length > 2;
}

function confirmou(texto) {
  return /\b(sim|s|ss|claro|ok|confirmo|correto|certo)\b/.test(texto);
}

if (curEstado === "SAUDACAO") {
  nextEstado = "COLETANDO_NOME";

} else if (curEstado === "COLETANDO_NOME") {
  if (msgOriginal.length > 2 && pareceNome(msgOriginal)) {
    dados.nome = msgOriginal;
    nextEstado = "COLETANDO_DOC";
  }

} else if (curEstado === "COLETANDO_DOC") {
  const tipo = detectarTipo(msg) || (extrairDoc(msgOriginal) ? extrairDoc(msgOriginal).tipo : null);
  const doc = extrairDoc(msgOriginal);
  if (tipo) dados.tipoPessoa = tipo;
  if (doc) dados.documento = doc.doc;
  if (!dados.tipoPessoa && doc) dados.tipoPessoa = doc.tipo;
  if (!dados.nome && pareceNome(msgOriginal) && msgOriginal.length < 50) {
    dados.nome = msgOriginal;
  }
  if (dados.documento || dados.tipoPessoa) {
    nextEstado = "CONFIRMACAO";
  }

} else if (curEstado === "CONFIRMACAO") {
  if (confirmou(msg)) {
    dados.finalizado = true;
    nextEstado = "ENCERRADO";
  }

} else if (curEstado === "ENCERRADO") {}

return [{
  json: {
    remetente: remetente,
    numero: numero,
    pushName: item.pushName || "",
    msg: msgOriginal,
    resposta: aiRes,
    estado: nextEstado,
    dados
  }
}];
